&lt;h5 id=&#34;int64-整数922337203685477580764-位整数-9223372036854775808-~-i8&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#int64-整数922337203685477580764-位整数-9223372036854775808-~-i8&#34;&gt;#&lt;/a&gt; int64 整数，9223372036854775807)^64 位整数 (-9223372036854775808 ~ ‘i8’&lt;/h5&gt;
