&lt;h5 id=&#34;层索引第二个list是内层索引&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#层索引第二个list是内层索引&#34;&gt;#&lt;/a&gt; 层索引，第二个 list 是内层索引。&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-29&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-29&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import pandas as pd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import numpy as np&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ser_obj = pd.Series(np.random.randn( 12 ),index=[&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[&amp;#x27;a&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;c&amp;#x27;, &amp;#x27;c&amp;#x27;, &amp;#x27;c&amp;#x27;, &amp;#x27;d&amp;#x27;, &amp;#x27;d&amp;#x27;, &amp;#x27;d&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 0 , 1 , 2 , 0 , 1 , 2 , 0 , 1 , 2 , 0 , 1 , 2 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(ser_obj)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-30&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-30&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;a 0 0.099174&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 -0.310414&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 -0.558047&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b 0 1.742445&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 1.152924&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 -0.725332&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c 0 -0.150638&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 0.251660&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 0.063387&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d 0 1.080605&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 0.567547&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 -0.154148&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dtype: float64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;multiindex-索引对象&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#multiindex-索引对象&#34;&gt;#&lt;/a&gt; MultiIndex 索引对象&lt;/h2&gt;
