&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#如果文件路径有中文，则需要知道参数engine=&amp;#x27;python&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data = pd.read_csv(&amp;#x27;d:/数据/food_rank.csv&amp;#x27;,engine=&amp;#x27;python&amp;#x27;,encoding=&amp;#x27;utf8&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data.head()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;name num&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 酥油茶 219.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 青稞酒 95.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 酸奶 62.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 糌粑 16.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 琵琶肉 2.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#建议文件路径和文件名，不要出现中文&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
