&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;0 a 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 a 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 a 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 a 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 b 0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 b 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7 b 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(df_obj.duplicated())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 True&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 True&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7 True&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dtype: bool&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
