&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(df_obj.drop_duplicates())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data1 data2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 a 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 a 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 b 0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 b 3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(df_obj.drop_duplicates(&amp;#x27;data2&amp;#x27;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data1 data2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 a 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 a 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 b 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;22-利用函数或映射进行数据转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#22-利用函数或映射进行数据转换&#34;&gt;#&lt;/a&gt; 2.2 利用函数或映射进行数据转换&lt;/h3&gt;
&lt;h5 id=&#34;根据map传入的函数对每行或每列进行转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#根据map传入的函数对每行或每列进行转换&#34;&gt;#&lt;/a&gt; 根据 map 传入的函数对每行或每列进行转换&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-40&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-40&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ser_obj = pd.Series(np.random.randint( 0 , 10 , 10 ))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(ser_obj)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;print(ser_obj.map(lambda x : x ** 2 ))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
