&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(ser_obj.map(lambda x : x ** 2))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7 16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8 49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dtype: int64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
