&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;key A B C D&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 K0 A0 B0 C0 D0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 K1 A1 B1 C1 D1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 K2 A2 B2 C2 D2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 K3 A3 B3 C3 D3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;示例代码-43&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-43&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;left = pd.DataFrame(&amp;#123;&amp;#x27;key1&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K2&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;key2&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;A&amp;#x27;: [&amp;#x27;A0&amp;#x27;, &amp;#x27;A1&amp;#x27;, &amp;#x27;A2&amp;#x27;, &amp;#x27;A3&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;B&amp;#x27;: [&amp;#x27;B0&amp;#x27;, &amp;#x27;B1&amp;#x27;, &amp;#x27;B2&amp;#x27;, &amp;#x27;B3&amp;#x27;]&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;right = pd.DataFrame(&amp;#123;&amp;#x27;key1&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K2&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;key2&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;C&amp;#x27;: [&amp;#x27;C0&amp;#x27;, &amp;#x27;C1&amp;#x27;, &amp;#x27;C2&amp;#x27;, &amp;#x27;C3&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;D&amp;#x27;: [&amp;#x27;D0&amp;#x27;, &amp;#x27;D1&amp;#x27;, &amp;#x27;D2&amp;#x27;, &amp;#x27;D3&amp;#x27;]&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pd.merge(left,right,on=[&amp;#x27;key1&amp;#x27;,&amp;#x27;key2&amp;#x27;]) #指定多个键，进行合并&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-44&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-44&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;key1 key2 A B C D&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 K0 K0 A0 B0 C0 D0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 K1 K0 A2 B2 C1 D1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 K1 K0 A2 B2 C2 D2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h6 id=&#34;指定左连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#指定左连接&#34;&gt;#&lt;/a&gt; #指定左连接&lt;/h6&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;left = pd.DataFrame(&amp;#123;&amp;#x27;key1&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K2&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;key2&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h6 id=&#34;a-a0-a1-a2-a3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#a-a0-a1-a2-a3&#34;&gt;#&lt;/a&gt; ‘A’: [‘A0’, ‘A1’, ‘A2’, ‘A3’],&lt;/h6&gt;
&lt;h6 id=&#34;b-b0-b1-b2-b3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#b-b0-b1-b2-b3&#34;&gt;#&lt;/a&gt; ‘B’: [‘B0’, ‘B1’, ‘B2’, ‘B3’]})&lt;/h6&gt;
&lt;p&gt;right = pd.DataFrame({‘key1’: [‘K0’, ‘K1’, ‘K1’, ‘K2’],&lt;br&gt;
‘key2’: [‘K0’, ‘K0’, ‘K0’, ‘K0’],&lt;br&gt;
‘C’: [‘C0’, ‘C1’, ‘C2’, ‘C3’],&lt;br&gt;
‘D’: [‘D0’, ‘D1’, ‘D2’, ‘D3’]})&lt;/p&gt;
&lt;p&gt;pd.merge(left, right, how=‘left’, on=[‘key1’, ‘key2’])&lt;br&gt;
key1 key2 A B C D&lt;br&gt;
0 K0 K0 A0 B0 C0 D0&lt;br&gt;
1 K0 K1 A1 B1 NaN NaN&lt;br&gt;
2 K1 K0 A2 B2 C1 D1&lt;br&gt;
3 K1 K0 A2 B2 C2 D2&lt;br&gt;
4 K2 K1 A3 B3 NaN NaN&lt;/p&gt;
&lt;h6 id=&#34;指定右连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#指定右连接&#34;&gt;#&lt;/a&gt; #指定右连接&lt;/h6&gt;
&lt;p&gt;left = pd.DataFrame({‘key1’: [‘K0’, ‘K0’, ‘K1’, ‘K2’],&lt;br&gt;
‘key2’: [‘K0’, ‘K1’, ‘K0’, ‘K1’],&lt;br&gt;
‘A’: [‘A0’, ‘A1’, ‘A2’, ‘A3’],&lt;br&gt;
‘B’: [‘B0’, ‘B1’, ‘B2’, ‘B3’]})&lt;br&gt;
right = pd.DataFrame({‘key1’: [‘K0’, ‘K1’, ‘K1’, ‘K2’],&lt;br&gt;
‘key2’: [‘K0’, ‘K0’, ‘K0’, ‘K0’],&lt;br&gt;
‘C’: [‘C0’, ‘C1’, ‘C2’, ‘C3’],&lt;br&gt;
‘D’: [‘D0’, ‘D1’, ‘D2’, ‘D3’]})&lt;br&gt;
pd.merge(left, right, how=‘right’, on=[‘key1’, ‘key2’])&lt;br&gt;
key1 key2 A B C D&lt;br&gt;
0 K0 K0 A0 B0 C0 D0&lt;br&gt;
1 K1 K0 A2 B2 C1 D1&lt;br&gt;
2 K1 K0 A2 B2 C2 D2&lt;br&gt;
3 K2 K0 NaN NaN C3 D3&lt;/p&gt;
&lt;h5 id=&#34;默认是内连接inner即结果中的键是交集&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#默认是内连接inner即结果中的键是交集&#34;&gt;#&lt;/a&gt; 默认是 “内连接”(inner)，即结果中的键是交集&lt;/h5&gt;
&lt;h5 id=&#34;how指定连接方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#how指定连接方式&#34;&gt;#&lt;/a&gt; how 指定连接方式&lt;/h5&gt;
&lt;h4 id=&#34;外连接-outer-结果中的键是并集&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#外连接-outer-结果中的键是并集&#34;&gt;#&lt;/a&gt; “外连接”(outer) ，结果中的键是并集&lt;/h4&gt;
&lt;h5 id=&#34;示例代码-44&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-44&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;left = pd.DataFrame(&amp;#123;&amp;#x27;key1&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K2&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;key2&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;A&amp;#x27;: [&amp;#x27;A0&amp;#x27;, &amp;#x27;A1&amp;#x27;, &amp;#x27;A2&amp;#x27;, &amp;#x27;A3&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;B&amp;#x27;: [&amp;#x27;B0&amp;#x27;, &amp;#x27;B1&amp;#x27;, &amp;#x27;B2&amp;#x27;, &amp;#x27;B3&amp;#x27;]&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;right = pd.DataFrame(&amp;#123;&amp;#x27;key1&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K1&amp;#x27;, &amp;#x27;K2&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;key2&amp;#x27;: [&amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;, &amp;#x27;K0&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;C&amp;#x27;: [&amp;#x27;C0&amp;#x27;, &amp;#x27;C1&amp;#x27;, &amp;#x27;C2&amp;#x27;, &amp;#x27;C3&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;D&amp;#x27;: [&amp;#x27;D0&amp;#x27;, &amp;#x27;D1&amp;#x27;, &amp;#x27;D2&amp;#x27;, &amp;#x27;D3&amp;#x27;]&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pd.merge(left,right,how=&amp;#x27;outer&amp;#x27;,on=[&amp;#x27;key1&amp;#x27;,&amp;#x27;key2&amp;#x27;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-45&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-45&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;key1 key2 A B C D&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 K0 K0 A0 B0 C0 D0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 K0 K1 A1 B1 NaN NaN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 K1 K0 A2 B2 C1 D1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 K1 K0 A2 B2 C2 D2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 K2 K1 A3 B3 NaN NaN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 K2 K0 NaN NaN C3 D3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;处理重复列名&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#处理重复列名&#34;&gt;#&lt;/a&gt; 处理重复列名&lt;/h4&gt;
&lt;h5 id=&#34;参数suffixes默认为_x-_y&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参数suffixes默认为_x-_y&#34;&gt;#&lt;/a&gt; 参数 suffixes：默认为_x, _y&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-45&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-45&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;h6 id=&#34;处理重复列名-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#处理重复列名-2&#34;&gt;#&lt;/a&gt; # 处理重复列名&lt;/h6&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df_obj1 = pd.DataFrame(&amp;#123;&amp;#x27;key&amp;#x27;: [&amp;#x27;b&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;c&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;b&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;data&amp;#x27; : np.random.randint( 0 , 10 , 7 )&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;df_obj2 = pd.DataFrame(&amp;#123;&amp;#x27;key&amp;#x27;: [&amp;#x27;a&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;d&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;data&amp;#x27; : np.random.randint( 0 , 10 , 3 )&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;print(pd.merge(df_obj1, df_obj2, on=&amp;#x27;key&amp;#x27;, suffixes=(&amp;#x27;_left&amp;#x27;, &amp;#x27;_right&amp;#x27;)))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-46&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-46&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;data_left key data_right&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 9 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 5 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 1 b 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 2 a 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 2 a 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 5 a 8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;按索引连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按索引连接&#34;&gt;#&lt;/a&gt; 按索引连接&lt;/h4&gt;
&lt;h5 id=&#34;参数left_indextrue或right_indextrue&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参数left_indextrue或right_indextrue&#34;&gt;#&lt;/a&gt; 参数 left_index=True 或 right_index=True&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-46&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-46&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;h6 id=&#34;按索引连接-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按索引连接-2&#34;&gt;#&lt;/a&gt; # 按索引连接&lt;/h6&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df_obj1 = pd.DataFrame(&amp;#123;&amp;#x27;key&amp;#x27;: [&amp;#x27;b&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;c&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;a&amp;#x27;, &amp;#x27;b&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;data1&amp;#x27; : np.random.randint( 0 , 10 , 7 )&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;df_obj2 = pd.DataFrame(&amp;#123;&amp;#x27;data2&amp;#x27; : np.random.randint( 0 , 10 , 3 )&amp;#125;, index=[&amp;#x27;a&amp;#x27;, &amp;#x27;b&amp;#x27;, &amp;#x27;d&amp;#x27;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;print(pd.merge(df_obj1, df_obj2, left_on=&amp;#x27;key&amp;#x27;, right_index=True))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-47&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-47&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
