&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(np.concatenate([arr1, arr2]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[[ 3 3 0 8 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 2 0 3 1 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 4 8 8 2 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 6 8 7 3 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 1 6 8 7 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 1 4 7 1 ]]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(np.concatenate([arr1, arr2], axis=1))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[[ 3 3 0 8 6 8 7 3 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 2 0 3 1 1 6 8 7 ]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ 4 8 8 2 1 4 7 1 ]]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;2-pdconcat&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-pdconcat&#34;&gt;#&lt;/a&gt; 2. pd.concat&lt;/h4&gt;
&lt;h5 id=&#34;注意指定轴方向默认axis0&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#注意指定轴方向默认axis0&#34;&gt;#&lt;/a&gt; 注意指定轴方向，默认 axis=0&lt;/h5&gt;
&lt;h5 id=&#34;join指定合并方式默认为outer&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#join指定合并方式默认为outer&#34;&gt;#&lt;/a&gt; join 指定合并方式，默认为 outer&lt;/h5&gt;
&lt;h5 id=&#34;series合并时查看行索引有无重复&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#series合并时查看行索引有无重复&#34;&gt;#&lt;/a&gt; Series 合并时查看行索引有无重复&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df1 = pd.DataFrame(np.arange( 6 ).reshape( 3 , 2 ),index=list(&amp;#x27;abc&amp;#x27;),columns=[&amp;#x27;one&amp;#x27;,&amp;#x27;two&amp;#x27;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df2 = pd.DataFrame(np.arange( 4 ).reshape( 2 , 2 )+ 5 ,index=list(&amp;#x27;ac&amp;#x27;),columns=[&amp;#x27;three&amp;#x27;,&amp;#x27;four&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pd.concat([df1,df2]) #默认外连接，axis=0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;four one three two&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a NaN 0.0 NaN 1.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b NaN 2.0 NaN 3.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c NaN 4.0 NaN 5.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a 6.0 NaN 5.0 NaN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c 8.0 NaN 7.0 NaN&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pd.concat([df1,df2],axis=&amp;#x27;columns&amp;#x27;) #指定axis=1连接&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;one two three four&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a 0 1 5.0 6.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b 2 3 NaN NaN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c 4 5 7.0 8.0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#同样我们也可以指定连接的方式为inner&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pd.concat([df1,df2],axis= 1 ,join=&amp;#x27;inner&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;one two three four&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a 0 1 5 6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c 4 5 7 8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;三-重塑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三-重塑&#34;&gt;#&lt;/a&gt; 三、重塑&lt;/h1&gt;
&lt;h2 id=&#34;1-stack&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-stack&#34;&gt;#&lt;/a&gt; 1. stack&lt;/h2&gt;
&lt;h5 id=&#34;将列索引旋转为行索引完成层级索引&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#将列索引旋转为行索引完成层级索引&#34;&gt;#&lt;/a&gt; 将列索引旋转为行索引，完成层级索引&lt;/h5&gt;
&lt;h5 id=&#34;dataframe-series&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dataframe-series&#34;&gt;#&lt;/a&gt; DataFrame-&amp;gt;Series&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-48&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-48&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import numpy as np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import pandas as pd&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df_obj = pd.DataFrame(np.random.randint( 0 , 10 , ( 5 , 2 )), columns=[&amp;#x27;data1&amp;#x27;, &amp;#x27;data2&amp;#x27;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(df_obj)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;stacked = df_obj.stack()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(stacked)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-49&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-49&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(df_obj)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data1 data2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 7 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 7 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 8 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 4 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 1 2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(stacked)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 data1 7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 data1 7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 data1 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 data1 4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 data1 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dtype: int64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;2-unstack&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-unstack&#34;&gt;#&lt;/a&gt; 2. unstack&lt;/h2&gt;
&lt;h5 id=&#34;将层级索引展开&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#将层级索引展开&#34;&gt;#&lt;/a&gt; 将层级索引展开&lt;/h5&gt;
&lt;h5 id=&#34;series-dataframe&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#series-dataframe&#34;&gt;#&lt;/a&gt; Series-&amp;gt;DataFrame&lt;/h5&gt;
&lt;h5 id=&#34;默认操作内层索引即level-1&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#默认操作内层索引即level-1&#34;&gt;#&lt;/a&gt; 默认操作内层索引，即 level=-1&lt;/h5&gt;
&lt;h5 id=&#34;示例代码-49&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码-49&#34;&gt;#&lt;/a&gt; 示例代码：&lt;/h5&gt;
&lt;h6 id=&#34;默认操作内层索引&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#默认操作内层索引&#34;&gt;#&lt;/a&gt; # 默认操作内层索引&lt;/h6&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;print(stacked.unstack())&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# 通过level指定操作索引的级别&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(stacked.unstack(level= 0 ))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;运行结果-50&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行结果-50&#34;&gt;#&lt;/a&gt; 运行结果：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(stacked.unstack())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data1 data2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 7 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 7 8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 8 9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3 4 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4 1 2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# print(stacked.unstack(level=0))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 1 2 3 4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data1 7 7 8 4 1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;data2 9 8 9 1 2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;数据聚合与分组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据聚合与分组&#34;&gt;#&lt;/a&gt; 数据聚合与分组&lt;/h1&gt;
&lt;h5 id=&#34;什么是分组聚合如图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#什么是分组聚合如图&#34;&gt;#&lt;/a&gt; 什么是分组聚合？如图：&lt;/h5&gt;
&lt;h5 id=&#34;groupby-bynoneas_indextrue&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#groupby-bynoneas_indextrue&#34;&gt;#&lt;/a&gt; groupby : (by=None,as_index=True)&lt;/h5&gt;
&lt;h5 id=&#34;by-根据什么进行分组用于确定-groupby-的组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#by-根据什么进行分组用于确定-groupby-的组&#34;&gt;#&lt;/a&gt; by : 根据什么进行分组，用于确定 groupby 的组&lt;/h5&gt;
&lt;h5 id=&#34;as_index-对于聚合输出返回以组便签为索引的对象仅对dataframe&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#as_index-对于聚合输出返回以组便签为索引的对象仅对dataframe&#34;&gt;#&lt;/a&gt; as_index : 对于聚合输出，返回以组便签为索引的对象，仅对 DataFrame&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df1 = pd.DataFrame(&amp;#123;&amp;#x27;fruit&amp;#x27;:[&amp;#x27;apple&amp;#x27;,&amp;#x27;banana&amp;#x27;,&amp;#x27;orange&amp;#x27;,&amp;#x27;apple&amp;#x27;,&amp;#x27;banana&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;color&amp;#x27;:[&amp;#x27;red&amp;#x27;,&amp;#x27;yellow&amp;#x27;,&amp;#x27;yellow&amp;#x27;,&amp;#x27;cyan&amp;#x27;,&amp;#x27;cyan&amp;#x27;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;price&amp;#x27;:[8.5,6.8,5.6,7.8,6.4]&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#查看类型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;type(df1.groupby(&amp;#x27;fruit&amp;#x27;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pandas.core.groupby.groupby.DataFrameGroupBy #GruopBy对象，它是一个包含组名，和数据块的 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;维元组序列，支持迭代&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for name, group in df1.groupby(&amp;#x27;fruit&amp;#x27;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(name) #输出组名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;apple&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;banana&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;orange&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;print(group) # 输出数据块&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;fruit color price&lt;br&gt;
0 apple red 8.5&lt;br&gt;
3 apple cyan 7.8&lt;br&gt;
fruit color price&lt;br&gt;
1 banana yellow 6.8&lt;br&gt;
4 banana cyan 6.4&lt;br&gt;
fruit color price&lt;br&gt;
2 orange yellow 5.6&lt;/p&gt;
&lt;p&gt;#输出 group 类型&lt;br&gt;
 print (type (group)) #数据块是 dataframe 类型&lt;br&gt;
 &amp;lt;class ‘pandas.core.frame.DataFrame’&amp;gt;&lt;br&gt;
&amp;lt;class ‘pandas.core.frame.DataFrame’&amp;gt;&lt;br&gt;
&amp;lt;class ‘pandas.core.frame.DataFrame’&amp;gt;&lt;/p&gt;
&lt;h6 id=&#34;选择任意的数据块&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#选择任意的数据块&#34;&gt;#&lt;/a&gt; #选择任意的数据块&lt;/h6&gt;
&lt;p&gt;dict (list (df1.groupby (‘fruit’)))[‘apple’] #取出 apple 组的数据块&lt;br&gt;
 fruit color price&lt;br&gt;
0 apple red 8.5&lt;br&gt;
3 apple cyan 7.8&lt;/p&gt;
&lt;h5 id=&#34;聚合&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#聚合&#34;&gt;#&lt;/a&gt; 聚合&lt;/h5&gt;
&lt;h5 id=&#34;函数名-描述-count-分组中非na值的数量-sum-非na值的和-mean-非&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#函数名-描述-count-分组中非na值的数量-sum-非na值的和-mean-非&#34;&gt;#&lt;/a&gt; | 函数名 | 描述 | | :— | :— | | count | 分组中非 NA 值的数量 | | sum | 非 NA 值的和 | | mean | 非&lt;/h5&gt;
&lt;h5 id=&#34;na值的平均值-median-非na值的中位数-std-var-标准差和方差-min-max-非na的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#na值的平均值-median-非na值的中位数-std-var-标准差和方差-min-max-非na的&#34;&gt;#&lt;/a&gt; NA 值的平均值 | | median | 非 NA 值的中位数 | | std, var | 标准差和方差 | | min, max | 非 NA 的&lt;/h5&gt;
&lt;h5 id=&#34;最小值最大值-prod-非na值的乘积-first-last-非na值的第一个最后一个&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最小值最大值-prod-非na值的乘积-first-last-非na值的第一个最后一个&#34;&gt;#&lt;/a&gt; 最小值，最大值 | | prod | 非 NA 值的乘积 | | first, last | 非 NA 值的第一个，最后一个 |&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#Groupby对象具有上表中的聚合方法&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#根据fruit来求price的平均值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;df1[&amp;#x27;price&amp;#x27;].groupby(df1[&amp;#x27;fruit&amp;#x27;]).mean()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fruit&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;apple 8.15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;banana 6.60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;orange 5.60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Name: price, dtype: float64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#或者&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;df1.groupby(&amp;#x27;fruit&amp;#x27;)[&amp;#x27;price&amp;#x27;].mean()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#as_index=False&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;df1.groupby(&amp;#x27;fruit&amp;#x27;,as_index=False)[&amp;#x27;price&amp;#x27;].mean()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fruit price&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 apple 8.15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 banana 6.60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 orange 5.60&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h6 id=&#34;&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#&#34;&gt;#&lt;/a&gt; “”&amp;quot;&lt;/h6&gt;
&lt;h6 id=&#34;如果我现在有个需求计算每种水果的差值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#如果我现在有个需求计算每种水果的差值&#34;&gt;#&lt;/a&gt; 如果我现在有个需求，计算每种水果的差值，&lt;/h6&gt;
&lt;h6 id=&#34;1上表中的聚合函数不能满足于我们的需求我们需要使用自定义的聚合函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1上表中的聚合函数不能满足于我们的需求我们需要使用自定义的聚合函数&#34;&gt;#&lt;/a&gt; 1. 上表中的聚合函数不能满足于我们的需求，我们需要使用自定义的聚合函数&lt;/h6&gt;
&lt;h6 id=&#34;2在分组对象中使用我们自定义的聚合函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2在分组对象中使用我们自定义的聚合函数&#34;&gt;#&lt;/a&gt; 2. 在分组对象中，使用我们自定义的聚合函数&lt;/h6&gt;
&lt;h6 id=&#34;-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#-2&#34;&gt;#&lt;/a&gt; “”&amp;quot;&lt;/h6&gt;
&lt;h6 id=&#34;定义一个计算差值的函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定义一个计算差值的函数&#34;&gt;#&lt;/a&gt; #定义一个计算差值的函数&lt;/h6&gt;
&lt;p&gt;def diff_value(arr):&lt;br&gt;
return arr.max() - arr.min()&lt;br&gt;
# 使用自定义聚合函数，我们需要将函数传递给 agg 或 aggregate 方法，我们使用自定义聚合函数时，会&lt;br&gt;
比我们表中的聚合函数慢的多，因为要进行函数调用，数据重新排列&lt;br&gt;
 df1.groupby (‘fruit’)[‘price’].agg (diff_value)&lt;br&gt;
fruit&lt;br&gt;
apple 0.7&lt;br&gt;
banana 0.4&lt;br&gt;
orange 0.0&lt;br&gt;
Name: price, dtype: float64&lt;/p&gt;
&lt;h1 id=&#34;pandas-中的时间序列&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#pandas-中的时间序列&#34;&gt;#&lt;/a&gt; Pandas 中的时间序列&lt;/h1&gt;
&lt;h5 id=&#34;时间序列time-series数据是一种重要的结构化数据形式-在多个时间点观察或测量到的任何&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间序列time-series数据是一种重要的结构化数据形式-在多个时间点观察或测量到的任何&#34;&gt;#&lt;/a&gt; 时间序列（time series）数据是一种重要的结构化数据形式，。在多个时间点观察或测量到的任何&lt;/h5&gt;
&lt;h5 id=&#34;时间都可以形成一段时间序列-很多时间-时间序列是固定频率的-也就是说-数据点是根据某&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间都可以形成一段时间序列-很多时间-时间序列是固定频率的-也就是说-数据点是根据某&#34;&gt;#&lt;/a&gt; 时间都可以形成一段时间序列。很多时间， 时间序列是固定频率的， 也就是说， 数据点是根据某&lt;/h5&gt;
&lt;h5 id=&#34;种规律定期出现的比如每-15-秒-时间序列也可以是不定期的-时间序列数据的意义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#种规律定期出现的比如每-15-秒-时间序列也可以是不定期的-时间序列数据的意义&#34;&gt;#&lt;/a&gt; 种规律定期出现的（比如每 15 秒。。。。）。时间序列也可以是不定期的。时间序列数据的意义&lt;/h5&gt;
&lt;h5 id=&#34;取决于具体的应用场景-主要由以下几种&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#取决于具体的应用场景-主要由以下几种&#34;&gt;#&lt;/a&gt; 取决于具体的应用场景。主要由以下几种：&lt;/h5&gt;
&lt;h5 id=&#34;时间戳timestamp特定的时刻&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间戳timestamp特定的时刻&#34;&gt;#&lt;/a&gt; 时间戳（timestamp），特定的时刻。&lt;/h5&gt;
&lt;h5 id=&#34;固定时期period如-2007-年-1-月或-2010-年全年&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#固定时期period如-2007-年-1-月或-2010-年全年&#34;&gt;#&lt;/a&gt; 固定时期（period），如 2007 年 1 月或 2010 年全年。&lt;/h5&gt;
&lt;h5 id=&#34;时间间隔interval由起始和结束时间戳表示-时期period可以被看做间隔&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间间隔interval由起始和结束时间戳表示-时期period可以被看做间隔&#34;&gt;#&lt;/a&gt; 时间间隔（interval），由起始和结束时间戳表示。时期（period）可以被看做间隔&lt;/h5&gt;
&lt;h5 id=&#34;interval的特例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#interval的特例&#34;&gt;#&lt;/a&gt; （interval）的特例。&lt;/h5&gt;
&lt;h2 id=&#34;1-时间和日期数据类型及其工具&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-时间和日期数据类型及其工具&#34;&gt;#&lt;/a&gt; 1. 时间和日期数据类型及其工具：&lt;/h2&gt;
&lt;h5 id=&#34;python标准库包含用于日期date和时间time数据的数据类型而且还有日历方面的功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#python标准库包含用于日期date和时间time数据的数据类型而且还有日历方面的功能&#34;&gt;#&lt;/a&gt; Python 标准库包含用于日期（date）和时间（time）数据的数据类型，而且还有日历方面的功能。&lt;/h5&gt;
&lt;h5 id=&#34;我们主要会用到datetime-time以及calendar模块-datetimedatetime也可以简写为datetime&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#我们主要会用到datetime-time以及calendar模块-datetimedatetime也可以简写为datetime&#34;&gt;#&lt;/a&gt; 我们主要会用到 datetime、time 以及 calendar 模块。datetime.datetime（也可以简写为 datetime）&lt;/h5&gt;
&lt;h5 id=&#34;是用得最多的数据类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#是用得最多的数据类型&#34;&gt;#&lt;/a&gt; 是用得最多的数据类型：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 10 ]: from datetime import datetime&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 11 ]: now = datetime.now()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 12 ]: now&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 12 ]: datetime.datetime( 2017 , 9 , 25 , 14 , 5 , 52 , 72973 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 13 ]: now.year, now.month, now.day&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 13 ]: ( 2017 , 9 , 25 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;datetime以毫秒形式存储日期和时间-timedelta表示两个datetime对象之间的时间差&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#datetime以毫秒形式存储日期和时间-timedelta表示两个datetime对象之间的时间差&#34;&gt;#&lt;/a&gt; datetime 以毫秒形式存储日期和时间。timedelta 表示两个 datetime 对象之间的时间差：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 14 ]: delta = datetime( 2011 , 1 , 7 ) - datetime( 2008 , 6 , 24 , 8 , 15 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 15 ]: delta&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 15 ]: datetime.timedelta( 926 , 56700 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 16 ]: delta.days&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 16 ]: 926&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 17 ]: delta.seconds&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 17 ]: 56700&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;可以给datetime对象加上或减去一个或多个timedelta这样会产生一个新对象&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#可以给datetime对象加上或减去一个或多个timedelta这样会产生一个新对象&#34;&gt;#&lt;/a&gt; 可以给 datetime 对象加上（或减去）一个或多个 timedelta，这样会产生一个新对象：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 18 ]: from datetime import timedelta&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 19 ]: start = datetime( 2011 , 1 , 7 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 20 ]: start + timedelta( 12 )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 20 ]: datetime.datetime( 2011 , 1 , 19 , 0 , 0 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 21 ]: start - 2 * timedelta( 12 )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 21 ]: datetime.datetime( 2010 , 12 , 14 , 0 , 0 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;字符串和-datetime-的相互转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字符串和-datetime-的相互转换&#34;&gt;#&lt;/a&gt; 字符串和 datetime 的相互转换&lt;/h2&gt;
&lt;h5 id=&#34;利用str或strftime方法传入一个格式化字符串datetime对象和pandas的timestamp对象稍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#利用str或strftime方法传入一个格式化字符串datetime对象和pandas的timestamp对象稍&#34;&gt;#&lt;/a&gt; 利用 str 或 strftime 方法（传入一个格式化字符串），datetime 对象和 pandas 的 Timestamp 对象（稍&lt;/h5&gt;
&lt;h5 id=&#34;后就会介绍可以被格式化为字符串&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#后就会介绍可以被格式化为字符串&#34;&gt;#&lt;/a&gt; 后就会介绍）可以被格式化为字符串：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 22 ]: stamp = datetime( 2011 , 1 , 3 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 23 ]: str(stamp)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 23 ]: &amp;#x27;2011-01-03 00:00:00&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 24 ]: stamp.strftime(&amp;#x27;%Y-%m-%d&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 24 ]: &amp;#x27;2011-01-03&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;datetimestrptime可以用这些格式化编码将字符串转换为日期&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#datetimestrptime可以用这些格式化编码将字符串转换为日期&#34;&gt;#&lt;/a&gt; datetime.strptime 可以用这些格式化编码将字符串转换为日期：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 26 ]: datetime.strptime(value, &amp;#x27;%Y-%m-%d&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 26 ]: datetime.datetime( 2011 , 1 , 3 , 0 , 0 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 27 ]: datestrs = [&amp;#x27;7/6/2011&amp;#x27;, &amp;#x27;8/6/2011&amp;#x27;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 28 ]: [datetime.strptime(x, &amp;#x27;%m/%d/%Y&amp;#x27;) for x in datestrs]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 28 ]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[datetime.datetime( 2011 , 7 , 6 , 0 , 0 ),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;datetime.datetime( 2011 , 8 , 6 , 0 , 0 )]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;datetimestrptime是通过已知格式进行日期解析的最佳方式-但是每次都要编写格式定义是很麻烦&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#datetimestrptime是通过已知格式进行日期解析的最佳方式-但是每次都要编写格式定义是很麻烦&#34;&gt;#&lt;/a&gt; datetime.strptime 是通过已知格式进行日期解析的最佳方式。但是每次都要编写格式定义是很麻烦&lt;/h5&gt;
&lt;h5 id=&#34;的事情尤其是对于一些常见的日期格式-这种情况下你可以用dateutil这个第三方包中的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#的事情尤其是对于一些常见的日期格式-这种情况下你可以用dateutil这个第三方包中的&#34;&gt;#&lt;/a&gt; 的事情，尤其是对于一些常见的日期格式。这种情况下，你可以用 dateutil 这个第三方包中的&lt;/h5&gt;
&lt;h5 id=&#34;parserparse方法pandas中已经自动安装好了&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#parserparse方法pandas中已经自动安装好了&#34;&gt;#&lt;/a&gt; parser.parse 方法（pandas 中已经自动安装好了）：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 29 ]: from dateutil.parser import parse&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 30 ]: parse(&amp;#x27;2011-01-03&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 30 ]: datetime.datetime( 2011 , 1 , 3 , 0 , 0 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;dateutil可以解析几乎所有人类能够理解的日期表示形式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dateutil可以解析几乎所有人类能够理解的日期表示形式&#34;&gt;#&lt;/a&gt; dateutil 可以解析几乎所有人类能够理解的日期表示形式：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 31 ]: parse(&amp;#x27;Jan 31, 1997 10:45 PM&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 31 ]: datetime.datetime( 1997 , 1 , 31 , 22 , 45 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;在国际通用的格式中日出现在月的前面很普遍传入dayfirsttrue即可解决这个问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在国际通用的格式中日出现在月的前面很普遍传入dayfirsttrue即可解决这个问题&#34;&gt;#&lt;/a&gt; 在国际通用的格式中，日出现在月的前面很普遍，传入 dayfirst=True 即可解决这个问题：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [ 32 ]: parse(&amp;#x27;6/12/2011&amp;#x27;, dayfirst=True)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[ 32 ]: datetime.datetime( 2011 , 12 , 6 , 0 , 0 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;pandas通常是用于处理成组日期的不管这些日期是dataframe的轴索引还是列-to_datetime方&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#pandas通常是用于处理成组日期的不管这些日期是dataframe的轴索引还是列-to_datetime方&#34;&gt;#&lt;/a&gt; pandas 通常是用于处理成组日期的，不管这些日期是 DataFrame 的轴索引还是列。to_datetime 方&lt;/h5&gt;
&lt;h5 id=&#34;法可以解析多种不同的日期表示形式-对标准日期格式如iso8601的解析非常快&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#法可以解析多种不同的日期表示形式-对标准日期格式如iso8601的解析非常快&#34;&gt;#&lt;/a&gt; 法可以解析多种不同的日期表示形式。对标准日期格式（如 ISO8601）的解析非常快：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [33]: datestrs = [&amp;#x27;2011-07-06 12:00:00&amp;#x27;, &amp;#x27;2011-08-06 00:00:00&amp;#x27;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [34]: pd.to_datetime(datestrs)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[34]: DatetimeIndex([&amp;#x27;2011-07-06 12:00:00&amp;#x27;, &amp;#x27;2011-08-06 00:00:00&amp;#x27;], dtype=&amp;#x27;dat&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;etime64[ns]&amp;#x27;, freq=None)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;它还可以处理缺失值none-空字符串等&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#它还可以处理缺失值none-空字符串等&#34;&gt;#&lt;/a&gt; 它还可以处理缺失值（None、空字符串等）：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [35]: idx = pd.to_datetime(datestrs + [None])&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [36]: idx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[36]: DatetimeIndex([&amp;#x27;2011-07-06 12:00:00&amp;#x27;, &amp;#x27;2011-08-06 00:00:00&amp;#x27;, &amp;#x27;NaT&amp;#x27;], dty&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pe=&amp;#x27;datetime64[ns]&amp;#x27;, freq=None)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [37]: idx[2]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[37]: NaT&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [38]: pd.isnull(idx)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[38]: array([False, False, True], dtype=bool)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;natnot-a-time是pandas中时间戳数据的null值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#natnot-a-time是pandas中时间戳数据的null值&#34;&gt;#&lt;/a&gt; NaT（Not a Time）是 pandas 中时间戳数据的 null 值。&lt;/h5&gt;
&lt;h3 id=&#34;2-时间序列基础&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-时间序列基础&#34;&gt;#&lt;/a&gt; 2. 时间序列基础&lt;/h3&gt;
&lt;h5 id=&#34;pandas最基本的时间序列类型就是以时间戳通常以python字符串或datatime对象表示为索引&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#pandas最基本的时间序列类型就是以时间戳通常以python字符串或datatime对象表示为索引&#34;&gt;#&lt;/a&gt; pandas 最基本的时间序列类型就是以时间戳（通常以 Python 字符串或 datatime 对象表示）为索引&lt;/h5&gt;
&lt;h5 id=&#34;的series&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#的series&#34;&gt;#&lt;/a&gt; 的 Series：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [39]: from datetime import datetime&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [40]: dates = [datetime(2011, 1, 2), datetime(2011, 1, 5),&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;....: datetime(2011, 1, 7), datetime(2011, 1, 8),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;....: datetime(2011, 1, 10), datetime(2011, 1, 12)]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [41]: ts = pd.Series(np.random.randn(6), index=dates)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;In [42]: ts&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Out[42]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-02 -0.204708&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-05 0.478943&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-07 -0.519439&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-08 -0.555730&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-10 1.965781&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2011-01-12 1.393406&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dtype: float64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;这些datetime对象实际上是被放在一个datetimeindex中的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#这些datetime对象实际上是被放在一个datetimeindex中的&#34;&gt;#&lt;/a&gt; 这些 datetime 对象实际上是被放在一个 DatetimeIndex 中的：&lt;/h5&gt;
