&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;movies = &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;流浪地球&amp;quot;:40.78,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;飞驰人生&amp;quot;:15.77,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;疯狂的外星人&amp;quot;:20.83,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;新喜剧之王&amp;quot;:6.10,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;廉政风云&amp;quot;:1.10,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;神探蒲松龄&amp;quot;:1.49,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;小猪佩奇过大年&amp;quot;:1.22,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;熊出没·原始时代&amp;quot;:6.71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.barh(np.arange(len(movies)),list(movies.values()))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.yticks(np.arange(len(movies)),list(movies.keys()),fontproperties=font)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.grid()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;效果图如下-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#效果图如下-4&#34;&gt;#&lt;/a&gt; 效果图如下：&lt;/h5&gt;
&lt;h2 id=&#34;分组条形图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分组条形图&#34;&gt;#&lt;/a&gt; 分组条形图：&lt;/h2&gt;
&lt;h5 id=&#34;现在有一组数据是-2019-年春节贺岁片前五天的电影票房记录&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#现在有一组数据是-2019-年春节贺岁片前五天的电影票房记录&#34;&gt;#&lt;/a&gt; 现在有一组数据，是 2019 年春节贺岁片前五天的电影票房记录。&lt;/h5&gt;
&lt;h5 id=&#34;示例代码如下-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例代码如下-3&#34;&gt;#&lt;/a&gt; 示例代码如下：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;movies = &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;流浪地球&amp;quot;:[2.01,4.59,7.99,11.83, 16 ],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;飞驰人生&amp;quot;:[3.19,5.08,6.73,8.10,9.35],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;疯狂的外星人&amp;quot;:[4.07,6.92,9.30,11.29,13.03],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;新喜剧之王&amp;quot;:[2.72,3.79,4.45,4.83,5.11],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;廉政风云&amp;quot;:[0.56,0.74,0.83,0.88,0.92],&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h6 id=&#34;神探蒲松龄066095110117123&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#神探蒲松龄066095110117123&#34;&gt;#&lt;/a&gt; “神探蒲松龄”:[0.66,0.95,1.10,1.17,1.23],&lt;/h6&gt;
&lt;h6 id=&#34;小猪佩奇过大年058081094101107&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小猪佩奇过大年058081094101107&#34;&gt;#&lt;/a&gt; “小猪佩奇过大年”:[0.58,0.81,0.94,1.01,1.07],&lt;/h6&gt;
&lt;h6 id=&#34;熊出没原始时代113196273342405&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#熊出没原始时代113196273342405&#34;&gt;#&lt;/a&gt; “熊出没・原始时代”:[1.13,1.96,2.73,3.42,4.05]&lt;/h6&gt;
&lt;h6 id=&#34;-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#-4&#34;&gt;#&lt;/a&gt; }&lt;/h6&gt;
&lt;p&gt;plt.figure(figsize=( 20 , 8 ))&lt;br&gt;
width = 0.75&lt;br&gt;
bin_width = width/ 5&lt;br&gt;
movie_pd = pd.DataFrame(movies)&lt;br&gt;
ind = np.arange( 0 ,len(movies))&lt;/p&gt;
&lt;p&gt;##### 第一种方案&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;first_day = movie_pd.iloc[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(ind-bin_width*&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,first_day,width=bin_width,label=&lt;span class=&#34;string&#34;&gt;&amp;#x27;第一天&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;second_day = movie_pd.iloc[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; plt.bar(ind-bin_width,second_day,width=bin_width,label=&lt;span class=&#34;string&#34;&gt;&amp;#x27;第二天&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;third_day = movie_pd.iloc[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(ind,third_day,width=bin_width,label=&lt;span class=&#34;string&#34;&gt;&amp;#x27;第三天&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;four_day = movie_pd.iloc[&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(ind+bin_width,four_day,width=bin_width,label=&lt;span class=&#34;string&#34;&gt;&amp;#x27;第四天&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;five_day = movie_pd.iloc[&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(ind+bin_width*&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,five_day,width=bin_width,label=&lt;span class=&#34;string&#34;&gt;&amp;#x27;第五天&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h6 id=&#34;第二种方案&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二种方案&#34;&gt;#&lt;/a&gt; # 第二种方案&lt;/h6&gt;
&lt;p&gt;for index in movie_pd.index:&lt;br&gt;
day_tickets = movie_pd.iloc[index]&lt;br&gt;
xs = ind-(bin_width*( 2 -index))&lt;br&gt;
 plt.bar (xs,day_tickets,width=bin_width,label=“第 % d 天”%(index+ 1 ))&lt;br&gt;
for ticket,x in zip(day_tickets,xs):&lt;br&gt;
plt.annotate(ticket,xy=(x,ticket),xytext=(x-0.1,ticket+0.1))&lt;/p&gt;
&lt;h6 id=&#34;设置图例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#设置图例&#34;&gt;#&lt;/a&gt; # 设置图例&lt;/h6&gt;
&lt;p&gt;plt.legend(prop=font)&lt;br&gt;
 plt.ylabel (“单位：亿”,fontproperties=font)&lt;br&gt;
 plt.title (“春节前 5 天电影票房记录”,fontproperties=font)&lt;/p&gt;
&lt;h1 id=&#34;设置x轴的坐标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#设置x轴的坐标&#34;&gt;#&lt;/a&gt; 设置 x 轴的坐标&lt;/h1&gt;
&lt;p&gt;plt.xticks(ind,movie_pd.columns,fontproperties=font)&lt;br&gt;
plt.xlim&lt;br&gt;
plt.grid(True)&lt;br&gt;
plt.show()&lt;/p&gt;
&lt;h5 id=&#34;示例图如下-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例图如下-3&#34;&gt;#&lt;/a&gt; 示例图如下：&lt;/h5&gt;
&lt;h2 id=&#34;堆叠条形图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#堆叠条形图&#34;&gt;#&lt;/a&gt; 堆叠条形图：&lt;/h2&gt;
&lt;h5 id=&#34;堆叠条形图是将一组相关的条形图堆叠在一起进行比较的条形图-比如以下案例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#堆叠条形图是将一组相关的条形图堆叠在一起进行比较的条形图-比如以下案例&#34;&gt;#&lt;/a&gt; 堆叠条形图，是将一组相关的条形图堆叠在一起进行比较的条形图。比如以下案例：&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;menMeans = ( 20 , 35 , 30 , 35 , 27 )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;womenMeans = ( 25 , 32 , 34 , 20 , 25 )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;groupNames = (&amp;#x27;G1&amp;#x27;,&amp;#x27;G2&amp;#x27;,&amp;#x27;G3&amp;#x27;,&amp;#x27;G4&amp;#x27;,&amp;#x27;G5&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;xs = np.arange(len(menMeans))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(xs,menMeans)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(xs,womenMeans,bottom=menMeans)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.xticks(xs,groupNames)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.show()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;效果图如下-5&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#效果图如下-5&#34;&gt;#&lt;/a&gt; 效果图如下：&lt;/h5&gt;
&lt;h5 id=&#34;在绘制女性得分的条形图的时候因为要堆叠在男性得分的条形图上所以使用到了一&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在绘制女性得分的条形图的时候因为要堆叠在男性得分的条形图上所以使用到了一&#34;&gt;#&lt;/a&gt; 在绘制女性得分的条形图的时候，因为要堆叠在男性得分的条形图上，所以使用到了一&lt;/h5&gt;
&lt;h5 id=&#34;个-bottom-参数就是距离-x-轴的距离-通过对贴条形图我们就可以清楚的知道哪一个队伍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#个-bottom-参数就是距离-x-轴的距离-通过对贴条形图我们就可以清楚的知道哪一个队伍&#34;&gt;#&lt;/a&gt; 个 bottom 参数，就是距离 x 轴的距离。通过对贴条形图，我们就可以清楚的知道，哪一个队伍&lt;/h5&gt;
&lt;h5 id=&#34;的综合排名是最高的并且在每个队伍中男女的得分情况&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#的综合排名是最高的并且在每个队伍中男女的得分情况&#34;&gt;#&lt;/a&gt; 的综合排名是最高的，并且在每个队伍中男女的得分情况。&lt;/h5&gt;
&lt;h2 id=&#34;条形图应用场景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#条形图应用场景&#34;&gt;#&lt;/a&gt; 条形图应用场景：&lt;/h2&gt;
&lt;h5 id=&#34;1-数量统计&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-数量统计&#34;&gt;#&lt;/a&gt; 1. 数量统计。&lt;/h5&gt;
&lt;h5 id=&#34;2-频率统计&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-频率统计&#34;&gt;#&lt;/a&gt; 2. 频率统计。&lt;/h5&gt;
&lt;h1 id=&#34;直方图-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#直方图-2&#34;&gt;#&lt;/a&gt; 直方图&lt;/h1&gt;
&lt;h5 id=&#34;直方图histogram又称质量分布图是一种统计报告图由一系列高度不等的条纹表示数据分-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#直方图histogram又称质量分布图是一种统计报告图由一系列高度不等的条纹表示数据分-2&#34;&gt;#&lt;/a&gt; 直方图 (Histogram)，又称质量分布图，是一种统计报告图，由一系列高度不等的条纹表示数据分&lt;/h5&gt;
&lt;h5 id=&#34;布的情况-一般用横轴表示数据类型纵轴表示分布情况-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#布的情况-一般用横轴表示数据类型纵轴表示分布情况-2&#34;&gt;#&lt;/a&gt; 布的情况。一般用横轴表示数据类型，纵轴表示分布情况。&lt;/h5&gt;
&lt;h5 id=&#34;直方图是数值数据分布的精确图形表示-为了构建直方图第一步是将值的范围分段即将整个值-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#直方图是数值数据分布的精确图形表示-为了构建直方图第一步是将值的范围分段即将整个值-2&#34;&gt;#&lt;/a&gt; 直方图是数值数据分布的精确图形表示。为了构建直方图，第一步是将值的范围分段，即将整个值&lt;/h5&gt;
&lt;h5 id=&#34;的范围分成一系列间隔然后计算每个间隔中有多少值-这些值通常被指定为连续的不重叠的变-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#的范围分成一系列间隔然后计算每个间隔中有多少值-这些值通常被指定为连续的不重叠的变-2&#34;&gt;#&lt;/a&gt; 的范围分成一系列间隔，然后计算每个间隔中有多少值。这些值通常被指定为连续的，不重叠的变&lt;/h5&gt;
&lt;h5 id=&#34;量间隔-间隔必须相邻并且通常是但不是必须的相等的大小-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#量间隔-间隔必须相邻并且通常是但不是必须的相等的大小-2&#34;&gt;#&lt;/a&gt; 量间隔。间隔必须相邻，并且通常是（但不是必须的）相等的大小。&lt;/h5&gt;
&lt;h2 id=&#34;绘制直方图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#绘制直方图&#34;&gt;#&lt;/a&gt; 绘制直方图：&lt;/h2&gt;
&lt;h5 id=&#34;直方图的绘制方法使用的是-plthist-方法来实现这个方法的参数以及返回值如下&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#直方图的绘制方法使用的是-plthist-方法来实现这个方法的参数以及返回值如下&#34;&gt;#&lt;/a&gt; 直方图的绘制方法，使用的是 plt.hist 方法来实现，这个方法的参数以及返回值如下：&lt;/h5&gt;
&lt;h5 id=&#34;参数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参数&#34;&gt;#&lt;/a&gt; 参数：&lt;/h5&gt;
&lt;h5 id=&#34;1-x-数组或者可以循环的序列-直方图将会从这组数据中进行分组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-x-数组或者可以循环的序列-直方图将会从这组数据中进行分组&#34;&gt;#&lt;/a&gt; 1. x ：数组或者可以循环的序列。直方图将会从这组数据中进行分组。&lt;/h5&gt;
&lt;h5 id=&#34;2-bins-数字或者序列数组列表等-如果是数字代表的是要分成多少组-如果是序&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-bins-数字或者序列数组列表等-如果是数字代表的是要分成多少组-如果是序&#34;&gt;#&lt;/a&gt; 2. bins ：数字或者序列（数组 / 列表等）。如果是数字，代表的是要分成多少组。如果是序&lt;/h5&gt;
&lt;h5 id=&#34;列那么就会按照序列中指定的值进行分组-比如-1234-那么分组的时候会按照三个&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#列那么就会按照序列中指定的值进行分组-比如-1234-那么分组的时候会按照三个&#34;&gt;#&lt;/a&gt; 列，那么就会按照序列中指定的值进行分组。比如 [1,2,3,4] ，那么分组的时候会按照三个&lt;/h5&gt;
&lt;h5 id=&#34;区间分成-3-组分别是-122334&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#区间分成-3-组分别是-122334&#34;&gt;#&lt;/a&gt; 区间分成 3 组，分别是 [1,2)/[2,3)/[3,4] 。&lt;/h5&gt;
&lt;h5 id=&#34;3-range-元组或者none如果为元组那么指定-x-划分区间的最大值和最小值-如&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-range-元组或者none如果为元组那么指定-x-划分区间的最大值和最小值-如&#34;&gt;#&lt;/a&gt; 3. range ：元组或者 None，如果为元组，那么指定 x 划分区间的最大值和最小值。如&lt;/h5&gt;
&lt;h5 id=&#34;果-bins-是一个序列那么-range-没有有没有设置没有任何影响&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#果-bins-是一个序列那么-range-没有有没有设置没有任何影响&#34;&gt;#&lt;/a&gt; 果 bins 是一个序列，那么 range 没有有没有设置没有任何影响。&lt;/h5&gt;
&lt;h5 id=&#34;4-density-默认是-false-如果等于-true-那么将会使用频率分布直方图-每个条形表示&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-density-默认是-false-如果等于-true-那么将会使用频率分布直方图-每个条形表示&#34;&gt;#&lt;/a&gt; 4. density ：默认是 False ，如果等于 True ，那么将会使用频率分布直方图。每个条形表示&lt;/h5&gt;
&lt;h5 id=&#34;的不是个数而是-频率组距-落在各组样本数据的个数称为频数频数除以样本总个数为频&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#的不是个数而是-频率组距-落在各组样本数据的个数称为频数频数除以样本总个数为频&#34;&gt;#&lt;/a&gt; 的不是个数，而是 频率 / 组距 （落在各组样本数据的个数称为频数，频数除以样本总个数为频&lt;/h5&gt;
&lt;h5 id=&#34;率&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#率&#34;&gt;#&lt;/a&gt; 率）。&lt;/h5&gt;
&lt;h5 id=&#34;5-cumulative-如果这个和-density-都等于-true-那么返回值的第一个参数会不断的累加&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-cumulative-如果这个和-density-都等于-true-那么返回值的第一个参数会不断的累加&#34;&gt;#&lt;/a&gt; 5. cumulative ：如果这个和 density 都等于 True ，那么返回值的第一个参数会不断的累加，&lt;/h5&gt;
&lt;h5 id=&#34;最终等于-1&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最终等于-1&#34;&gt;#&lt;/a&gt; 最终等于 1 。&lt;/h5&gt;
&lt;h5 id=&#34;6-其他参数请参考-httpsmatplotliborgapi_as_genmatplotlibpyplothisthtml&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6-其他参数请参考-httpsmatplotliborgapi_as_genmatplotlibpyplothisthtml&#34;&gt;#&lt;/a&gt; 6. 其他参数：请参考： &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9tYXRwbG90bGliLm9yZy9hcGkvX2FzX2dlbi9tYXRwbG90bGliLnB5cGxvdC5oaXN0Lmh0bWw=&#34;&gt;https://matplotlib.org/api/_as_gen/matplotlib.pyplot.hist.html&lt;/span&gt; 。&lt;/h5&gt;
&lt;h5 id=&#34;返回值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#返回值&#34;&gt;#&lt;/a&gt; 返回值：&lt;/h5&gt;
&lt;h5 id=&#34;1-n-数组-每个区间内值出现的个数如果-densitytrue-那么这个将返回的是-频率组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-n-数组-每个区间内值出现的个数如果-densitytrue-那么这个将返回的是-频率组&#34;&gt;#&lt;/a&gt; 1. n ：数组。每个区间内值出现的个数，如果 density=True ，那么这个将返回的是 频率 / 组&lt;/h5&gt;
&lt;h5 id=&#34;距&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#距&#34;&gt;#&lt;/a&gt; 距 。&lt;/h5&gt;
&lt;h5 id=&#34;2-bins-数组-区间的值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-bins-数组-区间的值&#34;&gt;#&lt;/a&gt; 2. bins ：数组。区间的值。&lt;/h5&gt;
&lt;h5 id=&#34;3-patches-数组-每根条的对象类型是-matplotlibpatchesrectangle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-patches-数组-每根条的对象类型是-matplotlibpatchesrectangle&#34;&gt;#&lt;/a&gt; 3. patches ：数组。每根条的对象，类型是 matplotlib.patches.Rectangle 。&lt;/h5&gt;
