an class=&#34;line&#34;&gt;patches,texts,autotexts = plt.pie(percents,labels=names,autopct=&amp;quot;%.2f%%&amp;quot;,explode=( 0 ,0.05&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;, 0 , 0 , 0 , 0 ))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for text in texts+autotexts:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.setp(text,fontproperties=font)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;text.set_fontsize( 10 )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for text in autotexts:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;text.set_color(&amp;quot;white&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
