&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sns.jointplot(x=&amp;quot;Height&amp;quot;,y=&amp;quot;Weight&amp;quot;,data=china_athletes,kind=&amp;quot;hex&amp;quot;,gridsize= 20 )&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;更多请参考-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#更多请参考-2&#34;&gt;#&lt;/a&gt; 更多请参考：&lt;/h5&gt;
&lt;h3 id=&#34;jointplot-其他常用参数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#jointplot-其他常用参数&#34;&gt;#&lt;/a&gt; jointplot 其他常用参数：&lt;/h3&gt;
&lt;h5 id=&#34;1-xydata-绘制图的数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-xydata-绘制图的数据&#34;&gt;#&lt;/a&gt; 1. x,y,data ：绘制图的数据。&lt;/h5&gt;
&lt;h5 id=&#34;2-kind-scatter-reg-resid-kde-hex&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-kind-scatter-reg-resid-kde-hex&#34;&gt;#&lt;/a&gt; 2. kind ： scatter 、 reg 、 resid 、 kde 、 hex 。&lt;/h5&gt;
&lt;h5 id=&#34;3-color-绘制元素的颜色&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-color-绘制元素的颜色&#34;&gt;#&lt;/a&gt; 3. color ：绘制元素的颜色。&lt;/h5&gt;
&lt;h5 id=&#34;4-height-图的大小图会是一个正方形&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-height-图的大小图会是一个正方形&#34;&gt;#&lt;/a&gt; 4. height ：图的大小，图会是一个正方形。&lt;/h5&gt;
&lt;h5 id=&#34;5-ratio-主图和副图的比例只能为一个整形&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-ratio-主图和副图的比例只能为一个整形&#34;&gt;#&lt;/a&gt; 5. ratio ：主图和副图的比例，只能为一个整形。&lt;/h5&gt;
