&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;fig,[ax1,ax2] = plt.subplots( &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; , &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; ,figsize=( &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt; , &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt; ))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sns.scatterplot(x=&lt;span class=&#34;string&#34;&gt;&amp;quot;total_bill&amp;quot;&lt;/span&gt;,y=&lt;span class=&#34;string&#34;&gt;&amp;quot;tip&amp;quot;&lt;/span&gt;,data=tips,ax=ax1)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sns.barplot(x=&lt;span class=&#34;string&#34;&gt;&amp;quot;day&amp;quot;&lt;/span&gt;,y=&lt;span class=&#34;string&#34;&gt;&amp;quot;total_bill&amp;quot;&lt;/span&gt;,data=tips,ax=ax2)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
