&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;RR 型&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323143903292.png&#34; alt=&#34;image-20220323143903292&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323144117377.png&#34; alt=&#34;image-20220323144117377&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;LR 型&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323144811320.png&#34; alt=&#34;image-20220323144811320&#34;&gt;&lt;/p&gt;
&lt;p&gt;具体操作步骤：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323144844183.png&#34; alt=&#34;image-20220323144844183&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;RL 型&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323144935495.png&#34; alt=&#34;image-20220323144935495&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h6 id=&#34;查找效率分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查找效率分析&#34;&gt;#&lt;/a&gt; 查找效率分析&lt;/h6&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323150406589.png&#34; alt=&#34;image-20220323150406589&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;哈夫曼树&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#哈夫曼树&#34;&gt;#&lt;/a&gt; 哈夫曼树&lt;/h5&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323152638270.png&#34; alt=&#34;image-20220323152638270&#34;&gt;&lt;/p&gt;
&lt;h6 id=&#34;定义-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定义-2&#34;&gt;#&lt;/a&gt; 定义&lt;/h6&gt;
&lt;ul&gt;
&lt;li&gt;相关概念&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://raw.githubusercontent.com/zhihao-a/blog-img/main/image-20220323151335767.png&#34; alt=&#34;image-20220323151335767&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;哈夫曼树的相关定义&lt;/p&gt;
&lt;p&gt;在含有 n 个带权叶节点的二叉树中 ，其中带权路径长度（WPL）最小的二叉树称为哈夫曼树，也称为最优二叉树&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h6 id=&#34;哈夫曼树的构造&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#哈夫曼树的构造&#34;&gt;#&lt;/a&gt; 哈夫曼树的构造&lt;/h6&gt;
